  1011→int
  1012→uccompatdecomp(const ac_uint4 *in, int inlen,
  1013→	       ac_uint4 **out, int *outlen, void *ctx)
  1014→{
  1015→    return uccanoncompatdecomp(in, inlen, out, outlen, 1, ctx);
